// ===== PERSISTENT STORAGE LAYER =====
const API = import.meta.env.PROD ? "/api" : "http://localhost:3456/api";
const DB = {
  async load(key, fallback) {
    try {
      const r = await fetch(`${API}/${key}`);
      if (!r.ok) return fallback;
      const data = await r.json();
      return data ?? fallback;
    } catch {
      // fallback to localStorage if server not running
      try { const r = localStorage.getItem(key); return r ? JSON.parse(r) : fallback; } catch { return fallback; }
    }
  },
  async save(key, data) {
    try {
      await fetch(`${API}/${key}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(data) });
    } catch {
      try { localStorage.setItem(key, JSON.stringify(data)); } catch (e) { console.error("Save error:", e); }
    }
  }
};

